package config

import (
	"os"
	"path/filepath"
	"testing"
)

func TestDefaults(t *testing.T) {
	cfg := Defaults()

	if cfg.Embedder.Backend != "ollama" {
		t.Errorf("default backend = %q, want %q", cfg.Embedder.Backend, "ollama")
	}
	if cfg.Embedder.Dimensions != 768 {
		t.Errorf("default dimensions = %d, want %d", cfg.Embedder.Dimensions, 768)
	}
	if cfg.Embedder.MaxTokens != 8192 {
		t.Errorf("default maxTokens = %d, want %d", cfg.Embedder.MaxTokens, 8192)
	}
	if cfg.Embedder.Ollama.Host != "http://localhost:11434" {
		t.Errorf("default ollama host = %q, want %q", cfg.Embedder.Ollama.Host, "http://localhost:11434")
	}
	if cfg.Knowledge.MaxChunkSize != 16000 {
		t.Errorf("default maxChunkSize = %d, want %d", cfg.Knowledge.MaxChunkSize, 16000)
	}
	if cfg.Search.BM25Weight != 0.4 {
		t.Errorf("default bm25Weight = %f, want %f", cfg.Search.BM25Weight, 0.4)
	}
	if cfg.Search.KNNWeight != 0.6 {
		t.Errorf("default knnWeight = %f, want %f", cfg.Search.KNNWeight, 0.6)
	}
	if cfg.Security.MaxFileSizeBytes != 1*1024*1024 {
		t.Errorf("default maxFileSize = %d, want %d", cfg.Security.MaxFileSizeBytes, 1*1024*1024)
	}
}

func TestLoadEmptyPath(t *testing.T) {
	cfg, err := Load("")
	if err != nil {
		t.Fatalf("Load empty path: %v", err)
	}
	if cfg.Embedder.Backend != "ollama" {
		t.Errorf("backend = %q, want %q", cfg.Embedder.Backend, "ollama")
	}
}

func TestLoadJSONFile(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "config.json")

	data := []byte(`{
		"embedder": {
			"model": "custom-model",
			"dimensions": 384
		},
		"indexPath": "<TMPDIR>/test.bleve"
	}`)

	if err := os.WriteFile(path, data, 0644); err != nil {
		t.Fatal(err)
	}

	cfg, err := Load(path)
	if err != nil {
		t.Fatalf("Load: %v", err)
	}

	if cfg.Embedder.Model != "custom-model" {
		t.Errorf("model = %q, want %q", cfg.Embedder.Model, "custom-model")
	}
	if cfg.Embedder.Dimensions != 384 {
		t.Errorf("dimensions = %d, want %d", cfg.Embedder.Dimensions, 384)
	}
	// Defaults should be preserved for unset fields
	if cfg.Embedder.Backend != "ollama" {
		t.Errorf("backend should default to ollama, got %q", cfg.Embedder.Backend)
	}
	if cfg.IndexPath != "<TMPDIR>/test.bleve" {
		t.Errorf("indexPath = %q, want %q", cfg.IndexPath, "<TMPDIR>/test.bleve")
	}
}

func TestLoadInvalidJSON(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "bad.json")

	if err := os.WriteFile(path, []byte("{invalid}"), 0644); err != nil {
		t.Fatal(err)
	}

	_, err := Load(path)
	if err == nil {
		t.Fatal("expected error for invalid JSON")
	}
}

func TestLoadMissingFile(t *testing.T) {
	_, err := Load("/nonexistent/config.json")
	if err == nil {
		t.Fatal("expected error for missing file")
	}
}

func TestEnvOverrides(t *testing.T) {
	t.Setenv("RAG_MCP_EMBEDDER_BACKEND", "onnx")
	t.Setenv("RAG_MCP_OLLAMA_HOST", "http://custom:11434")
	t.Setenv("RAG_MCP_EMBEDDER_DIMENSIONS", "384")

	cfg, err := Load("")
	if err != nil {
		t.Fatalf("Load: %v", err)
	}

	if cfg.Embedder.Backend != "onnx" {
		t.Errorf("backend = %q, want %q", cfg.Embedder.Backend, "onnx")
	}
	if cfg.Embedder.Ollama.Host != "http://custom:11434" {
		t.Errorf("host = %q, want %q", cfg.Embedder.Ollama.Host, "http://custom:11434")
	}
	if cfg.Embedder.Dimensions != 384 {
		t.Errorf("dimensions = %d, want %d", cfg.Embedder.Dimensions, 384)
	}
}
